#!/bin/bash
set -e
echo "=== CMDB Enterprise Setup ==="
mkdir -p server public

echo "[1/7] docker-compose.yml"
cat > docker-compose.yml << 'EOF'
services:
  cmdb:
    build: .
    container_name: cmdb-enterprise
    restart: unless-stopped
    ports:
      - "3000:3000"
    volumes:
      - cmdb-data:/data
    environment:
      - PORT=3000
      - DATA_DIR=/data
      - SESSION_SECRET=mude-esta-chave-em-producao-2024
    healthcheck:
      test: ["CMD", "wget", "-qO-", "http://localhost:3000/api/auth/me"]
      interval: 30s
      timeout: 5s
      retries: 3

  kavita:
    image: jvmilazz0/kavita:latest
    container_name: kavita
    restart: unless-stopped
    ports:
      - "5000:5000"
    volumes:
      - /data/livros:/manga
      - kavita-config:/kavita/config
    environment:
      - TZ=America/Sao_Paulo

volumes:
  cmdb-data:
    driver: local
  kavita-config:
    driver: local
EOF

echo "[2/7] Dockerfile"
cat > Dockerfile << 'EOF'
FROM node:20-alpine
WORKDIR /app
COPY server/package*.json ./
RUN npm install --omit=dev
COPY server/server.js ./
COPY public/ ./public/
VOLUME ["/data"]
ENV DATA_DIR=/data
ENV PORT=3000
EXPOSE 3000
HEALTHCHECK --interval=30s --timeout=5s --start-period=10s \
  CMD wget -qO- http://localhost:3000/api/auth/me || exit 1
CMD ["node", "server.js"]
EOF

echo "[3/7] server/package.json"  ; echo ""   | base64 -d > server/package.json
echo "[4/7] server/server.js"     ; echo ""  | base64 -d > server/server.js
echo "[5/7] public/cmdb.html"     ; echo ""        | base64 -d > public/cmdb.html
echo "[6/7] public/cmdbAPI.js"    ; echo ""      | base64 -d > public/cmdbAPI.js
echo "[7/7] public/cmdb-agent.ps1"; echo ""   | base64 -d > public/cmdb-agent.ps1

echo ""
sudo mkdir -p /data/livros
echo "=== Subindo containers... ==="
docker compose up -d --build
echo ""
IP=$(hostname -I | awk '{print $1}')
echo "=== Pronto! ==="
echo "CMDB:       http://${IP}:3000"
echo "Biblioteca: http://${IP}:5000 (direto) ou via aba Biblioteca no CMDB"
